package dev.modichamiya.eclipse.gameplay.dungeon;

import java.time.*;
import java.util.*;

public final class DungeonRun {public enum State{PROVISIONING,ACTIVE,COMPLETED,FAILED,CLOSED}private final UUID id=UUID.randomUUID();private final DungeonDefinition definition;private final Set<UUID>party;private final Instant started;private final Set<String>cleared=new HashSet<>(),secrets=new HashSet<>();private int deaths;private State state=State.PROVISIONING;public DungeonRun(DungeonDefinition definition,Set<UUID>party,Instant started){this.definition=Objects.requireNonNull(definition);this.party=Set.copyOf(party);this.started=started;if(party.size()<definition.partyMin()||party.size()>definition.partyMax())throw new IllegalArgumentException("Party size");}public synchronized void activate(){if(state!=State.PROVISIONING)throw new IllegalStateException();state=State.ACTIVE;}public synchronized void clearRoom(String id,boolean secret){if(state!=State.ACTIVE)throw new IllegalStateException();cleared.add(id);if(secret)secrets.add(id);}public synchronized void death(){deaths++;}public synchronized int complete(Instant now){if(state!=State.ACTIVE)throw new IllegalStateException();state=State.COMPLETED;long seconds=Duration.between(started,now).getSeconds();return Math.max(0,10000-(int)seconds*10-deaths*250+secrets.size()*500);}public synchronized State state(){return state;}public UUID id(){return id;}public Set<UUID>party(){return party;}}
